from collections import defaultdict
from pathlib import Path
import csv
import importlib.util
import json
import sys

ROOT = Path(__file__).resolve().parents[1]


def load_parser():
    path = ROOT / "scripts" / "render-previews.py"
    spec = importlib.util.spec_from_file_location("preview_parser", path)
    module = importlib.util.module_from_spec(spec)
    sys.modules["preview_parser"] = module
    assert spec.loader
    spec.loader.exec_module(module)
    return module


