TYPE_LABELS = {
    "systemLandscape": "ландшафт систем",
    "systemContext": "системний контекст",
    "container": "контейнери",
    "component": "компоненти",
    "custom": "логічна/контрактна модель",
    "dynamic": "динамічний сценарій",
    "deployment": "розгортання",
}


def group_elements(refs, elements):
    grouped = defaultdict(list)
    for ref in sorted(refs, key=lambda r: elements[r].name if r in elements else r):
        e = elements.get(ref)
        if not e:
            continue
        grouped[e.kind].append(e.name)
    return grouped


def bullets(items):
    return "\n".join(f"- {item}" for item in items)


def generate_catalog(views, elements, relationships, parser):
    lines = [
        "# Каталог і текстовий опис C4-діаграм",
        "",
        "Цей розділ є текстовою специфікацією всіх подань архітектури. Авторитетним машинозчитуваним джерелом залишається `workspace.dsl`; графічні SVG/PNG у каталозі `previews` є похідними засобами перегляду.",
        "",
        "Кожна діаграма відповідає окремому архітектурному питанню. Повне контейнерне подання свідомо є щільним; для розгляду конкретних потоків слід використовувати фокусні C2, C3 та DYN-подання.",
        "",
    ]
    json_rows = []
    csv_rows = []
    for index, view in enumerate(views, 1):
        d = DETAILS[view.key]
        refs = parser.view_elements(view, elements)
        grouped = group_elements(refs, elements)
        rel_count = 0
        if view.kind == "dynamic":
            rel_count = len(view.steps)
        else:
            rel_count = sum(1 for r in relationships if r.source in refs and r.destination in refs)
        lines.extend([
            f"## {index}. {view.title}",
            "",
            f"**Ключ Structurizr:** `{view.key}`  ",
            f"**Тип подання:** {TYPE_LABELS.get(view.kind, view.kind)}  ",
            f"**Стислий зміст:** {view.description}",
            "",
            f"**Призначення.** {d['purpose']}",
            "",
            f"**Як читати діаграму.** {d['reading']}",
            "",
            f"**Ключові архітектурні рішення.** {d['decisions']}",
            "",
            f"**Безпека, приватність і відмовостійкість.** {d['safety']}",
            "",
            f"**Основна аудиторія.** {d['audience']}",
            "",
        ])
        if view.kind == "dynamic":
            lines.append("**Послідовність взаємодій:**")
            lines.append("")
            for step_no, step in enumerate(view.steps, 1):
                src = elements.get(step.source)
                dst = elements.get(step.destination)
                order = step.order or str(step_no)
                lines.append(f"{order}. **{src.name if src else step.source} → {dst.name if dst else step.destination}:** {step.description}")
            lines.append("")
        else:
            labels = {
                "person": "Ролі",
                "softwareSystem": "Програмні системи",
                "container": "Контейнери",
                "component": "Компоненти",
                "element": "Логічні елементи",
                "deploymentNode": "Вузли розгортання",
                "infrastructureNode": "Інфраструктурні вузли",
                "containerInstance": "Екземпляри контейнерів",
                "softwareSystemInstance": "Екземпляри систем",
            }
            compact = []
            for kind, names in grouped.items():
                if kind in {"deploymentEnvironment", "deploymentGroup"}:
                    continue
                compact.append(f"**{labels.get(kind, kind)}:** " + "; ".join(names))
            if compact:
                lines.append("**Склад подання.** " + "  \n".join(compact))
                lines.append("")
        lines.extend([
            f"**Обсяг подання:** {len(refs)} елементів; {rel_count} відношень або кроків.",
            "",
            f"[SVG-перегляд](../previews/svg/{view.key}.svg) · [PNG-перегляд](../previews/png/{view.key}.png)",
            "",
            "---",
            "",
        ])
        row = {
            "number": index,
            "key": view.key,
            "type": view.kind,
            "title": view.title,
            "description": view.description,
            "purpose": d["purpose"],
            "reading": d["reading"],
            "decisions": d["decisions"],
            "safety": d["safety"],
            "audience": d["audience"],
            "elementCount": len(refs),
            "relationshipOrStepCount": rel_count,
            "svg": f"previews/svg/{view.key}.svg",
            "png": f"previews/png/{view.key}.png",
        }
        json_rows.append(row)
        csv_rows.append({k: row[k] for k in ["number", "key", "type", "title", "description", "elementCount", "relationshipOrStepCount", "svg", "png"]})
    (ROOT / "docs" / "04-diagram-catalog.md").write_text("\n".join(lines), encoding="utf-8")
    (ROOT / "diagram-catalog.json").write_text(json.dumps(json_rows, ensure_ascii=False, indent=2), encoding="utf-8")
    with (ROOT / "diagram-catalog.csv").open("w", encoding="utf-8-sig", newline="") as fh:
        writer = csv.DictWriter(fh, fieldnames=csv_rows[0].keys())
        writer.writeheader(); writer.writerows(csv_rows)


def main():
    parser = load_parser()
    lines = (ROOT / "workspace-single-file.dsl").read_text(encoding="utf-8").splitlines()
    ms, me = parser.find_block(lines, r"^\s*model\s*\{")
    vs, ve = parser.find_block(lines, r"^\s*views\s*\{")
    elements, short = parser.parse_elements(lines, ms, me)
    relationships = parser.parse_relationships(lines, ms, me, elements, short)
    views = parser.parse_views(lines, vs, ve, elements, short)
    missing = [v.key for v in views if v.key not in DETAILS]
    extra = sorted(set(DETAILS) - {v.key for v in views})
    if missing or extra:
        raise SystemExit(f"Catalogue metadata mismatch. Missing={missing}; extra={extra}")
    generate_catalog(views, elements, relationships, parser)
    print(f"Generated catalogue for {len(views)} diagrams")


if __name__ == "__main__":
    main()
